INSERT INTO `paper_review` VALUES (1, 1, '测试——信息学院试卷实质审查表', '/profile/upload/2026/04/10/测试——信息学院试卷实质审查表_20260410182725A008.docx', 16861, '计算机与信息工程学院试卷实质审查表\n（2025/2026学年第2学期）\n\n课程名称	Java程序设计	课程性质	专业核心课\n使用班级	计算机科学与技术2023级1班\n任课教师	李老师\n试卷题型与比例	选择题	填空题	编程题	综合设计题\n20%	20%	40%	20%\n重复比例	AB卷重复比例(%)	历年重复比例(%)\n10%	8%\n教学目标	试卷中的题目编号（须全部覆盖）\n教学目标1		描述: 掌握Java基础语法与数据类型	支撑点：1、2、3、4、5\n教学目标2	描述: 理解面向对象三大特性	支撑点： 6、7、8、9\n教学目标3	描述: 能够编写简单Java程序	支撑点：10、11、12\n教学目标4	描述: 具备异常处理与IO编程能力	支撑点： 13、14\n教学目标5	描述: 完成小型项目综合设计	支撑点： 15\n审查结果	题型比例合理	重复比例合理	是否全部覆盖\n是	是	是\n课程负责人签字：\n试卷内容和比例符合学校和学院相关规定，同意送印。			系室主任签字：\n\n每个小题必须且只能支撑一个教学目标，所有教学目标支撑点分值总和必须和试卷总分保持一致。\n试卷题型包括选择题、填空题、分析题、设计题等，可以根据实际情况增加列数。\n3、教学目标编号与课程教学大纲一致，可以根据需要增加行数。\n4、课程负责人必须手签字和A、B卷一起送至信息楼329杨倩处。\n', '0', '0', '', '2026-04-10 18:27:38', '', NULL, NULL);

