INSERT INTO `syllabus` VALUES (3, 1, '《数据库应用》教学大纲-韩培友.doc', '/profile/upload/2026/04/08/《数据库应用》教学大纲-韩培友_20260408205358A011.doc', 78848, '课程设计《数据库应用》教学大纲\n一、基本信息\n课程代码：	1266511	课程性质：	专业核心课\n课程名称：	课程设计（数据库应用）	英文名称：	Curriculum Design (Database Applications)\n学时/学分：	40/1	开课时间：	大二(上)\n适用对象：	计算机科学、网络工程、软件工程、信息安全、电子商务、物流等专业等\n先修课程：	数据结构、数据库原理、高级程序设计语言\n大纲执笔人：	韩培友	大纲审核人：	谢波\n修订时间：	2016.3	当前版本：	2016\n\n二、课程描述\n本课程为一门专业核心课，主要面向计算机科学与技术、网络工程、软件工程、信息安全等专业本科低年级学生。本课程是《数据库原理》的实践课程，以数据库原理所对应的教材为主要教学内容。要求熟练掌握、加深理解并巩固《数据库原理》课程中所学到的基本概念、基本理论、基本原理和实现技术；综合应用数据库系统的原理和技术，以及其它课程的有关知识，设计并实现一个应用数据库管理系统；培养分析问题、解决问题的能力，进一步提高进行大型数据库管理系统设计的能力。\n\n三、教学目标\n通过本课程的实验教学和相关实验训练，使学生具备如下能力：\n1、掌握数据库原理的基本概念、基本理论、基本方法和实现技术。\n2、熟练掌握数据库系统的设计方法和设计步骤。\n3、熟练掌握需求分析和概念结构设计的方法和步骤。\n4、熟练掌握逻辑结构和物理结构的设计理论和实现技术。\n5、熟练掌握能够系统保护的设计理论和实现技术。\n6、熟练掌握能够数据库系统的实施、测试、运行和维护技术。\n\n四、课程目标对毕业要求的支撑\n毕业要求	指标点	课程目标\n掌握数据库原理的基本理论、基本方法和应用技术	具有扎实的数据库技术的基本概念、基本理论、基本方法和实现技术	教学目标1\n熟练掌握需求分析和概念结构的设计方法和步骤。	具有绘制数据流图、记录数据字典和绘制E-R图的能力	教学目标2\n掌握逻辑结构和物理结构的设计技术	能够把E-R图转换为关系模式，具有数据完整性和3NF与BCNF设计能力	教学目标3\n掌握系统保护的设计理论和实现技术	具有安全机制、并发机制和数据恢复机制的设计能力	教学目标4\n熟练掌握DBS的实施、测试、运行和维护技术	能够进行大型数据库系统的设计、开发、应用和维护	教学目标5\n\n五、教学内容\n实验1 数据库概念结构设计			 （支撑课程目标1、2）\n重点内容：需求分析的任务、方法和步骤。数据字典的概念、组成和格式。概念结构设计的三要素。概念结构的E-R图表示方法、概念结构设计的基本内容、概念结构的设计方法、概念结构的设计步骤。\n难点内容：数据字典的概念、组成和格式。数据流图与数据流图的绘制方法。概念结构的设计过程。\n教学内容：掌握数据库设计的系统规划、需求分析、数据流图和数据字典的基本概念、基本理论和实施方法。掌握数据库系统设计的概念结构设计理论。概念结构设计的三要素：属性、实体和联系。概念结构的E-R图表示方法、概念结构设计的基本内容、概念结构的设计方法、概念结构的设计步骤和过程。\n（1）需求分析的任务、方法和步骤。\n（2）数据流图及其绘制方法。\n（3）数据字典的概念、组成和格式。\n（4）属性、实体和联系的基本概念。\n（5）概念结构设计的基本内容。\n（6）概念结构的E-R图表示方法。\n（7）概念结构的设计方法和步骤。\n\n实验2 数据库设计		 	（支撑课程目标1、3）\n重点内容：逻辑结构设计的基本概念和基本理论，逻辑结构的设计过程。索引机制、存取方法、存储结构、存储介质和评价方法。SQL Servedr 2008提供的索引机制\n难点内容：逻辑结构设计的基本理论，逻辑结构的设计过程。平衡树索引（Balance Tree，B树）、聚簇（Cluster）索引和散列（Hash，哈希）索引。\n教学内容：掌握数据库系统逻辑结构设计的基本概念和基本理论，逻辑结构的设计过程。\n基本概念主要包括：笛卡尔积、关系、关系模式、关系数据库、候选键、主键、函数依赖、完全函数依赖、部分函数依赖、传递依赖、逻辑结构设计、属性、实体、联系、属性集闭包、函数依赖闭包、范式、保依赖、保连接、关系模式分解等。\n基本理论主要包括：实体的一对一、一对多和多对多联系；实体完整性、参照完整性、用户定义的完整性、数据完整性；1NF、2NF、3NF、BCNF、4NF、关系模式规范化；计算函数依赖的闭包；确定关系模式的候选键；计算属性集合的闭包；计算最小函数依赖集；关系模式的保连接分解、保依赖分解和既保连接又保依赖分解、关系范式分解算法等。\n掌握物理结构设计的基本概念、基本内容和基本方法。重点掌握索引机制（特别是B+树）及其用法和SQL Servedr 2008提供的索引机制。\n（1）E-R图向关系模型转换。\n（2）数据完整性设计（实体完整性、参照完整性、用户定义完整性及其规则）。\n（3）关系模式的规范化（范式、1NF、2NF、3NF、BCNF、4NF、关系模式规范化、范式保连接或者保依赖分解、范式分解算法）。\n（4）外模式设计的概念与内容。\n（5）常用的存取方法。\n（6）常用的存储介质及其选取原则。\n（7）物理结构的评价方法。\n（8）索引的建立方法、修改方法和删除方法。\n\n实验3 系统保护设计			 （支撑课程目标1、4）\n重点内容：并发控制和数据库恢复的关键技术。\n难点内容：并发控制和数据库恢复的具体实现技术。\n教学内容：掌握数据库系统的安全保护、并发控制和数据库恢复等数据库保护技术。\n（1）计算机系统安全和数据库系统安全。\n（2）SQL Server的安全控制。\n（3）事务管理机制（事务的概念、事务的ACID特性）。\n（4）封锁和封锁协议。\n（5）两段锁些和并发事务的可串行化调度\n（6）活锁和死锁（活锁和死锁的概念、预防、检测和解除）。\n（7）故障管理（事务故障、系统故障、介质故障、病毒故障及其恢复机制）。\n（8）数据转储机制（静态转储、动态转储；海量转储、增量转储）。\n（9）日志文件管理机制（日志文件的概念、分类、登记规则）。\n\n实验4 数据库系统设计与实现			 （支撑课程目标1、5）\n重点内容：\n（1）基于ODBC的数据源配置和数据库连接技术\n（2）SQL Server 2008环境下数据库和数据表的建立\n（3）基于主语言的SQL Server 2008数据库管理方法\n（4）如何使用关系代数表达式来表达实际查询问题。\n（5）如何使用元组演算表达式来表达实际查询问题。\n（6）如何使用域演算表达式来表达实际查询问题。\n（7）如何将关系代数表达式转换为元组演算表达式或转换为域演算表达式。\n（8）如何使用SQL Server语句来实现实际查询。\n（9）系统维护的类型和系统维护的内容。\n难点内容：嵌入式SQL的语句与主语言之间的通讯，游标管理；数据库互连，ODBC和API工作原理。系统维护的内容\n教学内容：掌握数据库系统实施和测试阶段，数据库系统实施的基本理论和实现技术；数据库系统测试的基本理论和实现技术。同时掌握服务器与数据库的连接、数据库的创建及其数据的入库、数据库系统功能设计、数据库系统GUI设计、数据库系统集成、数据库系统测试，一直到数据库系统的试运行等整个应用系统的实施过程。掌握数据库系统的运行管理、系统评价和系统维护技术。掌握SQL Server 2008 Integration Services集成任务的内容、功能和使用方法等运行与维护机制。\n（1）基于ODBC的数据源配置和数据库连接技术与实现方法。\n（2）SQL Server 2008环境下数据库及其数据表的建立。\n（3）基于主语言的SQL Server 2008数据库管理方法。\n（4）数据库系统功能设计（引导模块设计、加密模块设计、添加模块设计、修改模块设计、删除模块设计、查询模块设计、视图模块设计、报表模块设计和帮助模块设计）。\n（5）数据库系统GUI设计。\n（6）数据库系统集成与调试\n（7）数据库系统测试与试运行\n（8）系统运行管理（人员培训与场所准备；系统的安装与调试；整理基础数据；新旧系统切换；系统运行管理）。\n（9）系统评价与维护：系统评价的内容和报告；系统维护的类型和内容。\n\n实验5 系统验收			 （支撑课程目标1、2、3、4、5）\n重点内容：数据流图、数据字典、E-R图、数据完整性验证、关系模式的3NF验证、系统功能实现、系统性能指标验证\n难点内容：数据字典、E-R图、数据完整性验证、关系模式的3NF验证。\n教学内容：按照数据库系统规范要求进行数据库建设和应用程序开发。\n（1）对特定应用领域进行用户需求分析，包括数据需求和功能需求，形成需求文档。\n（2）利用E/R方法或ODL方法为特定应用领域设计概念模式，再转换成关系模式，形成数据库设计文档。\n（3）加载特定应用领域的足够数量的实验数据，以便充分展示所开发的应用程序的各种功能和运行效率。\n（4）开发数据库应用程序，形成程序功能文档。根据特定应用领域的要求，应用程序必须功能完备，使用方便（用户界面友好）。\n\n六、教学安排\n该课程每周40学时，1周， 40学时为实验教学时间。安排在教学周结束后的第一周。\n建议实验教学进度如下：\n章节	学时数\n实验1 数据库概念结构设计	8\n实验2 数据库设计	8\n实验3 系统保护设计		8\n实验4 数据库系统设计与实现	8\n实验5 系统验收		8\n\n七、课内实验内容、要求及学时\n因为本课程为实验教学课程，属于基础实验单独开设，所以不安排课内实验。\n\n八、教学方法与手段\n以实验实践教学为主，以理论指导为辅。在实验过程中注重能力的培养，以实际应用系统为案例，提高理论教学的实用性和应用性，提高学生分析和解决实际问题的能力。\n以学生独立设计、上机实践和实际操作为主，以老师指导为辅。按照E-R关系模式设计、3NF、数据库的建立、数据库操作设计、数据库的完整性约束和安全性控制的数据库设计的一般步骤，在一周内完成数据库设计和实施，并独立设计和实现一个典型的关系数据库系统。\n利用数据库原理的基本理论和基本技术，在老师的指导下，以实际应用为例，完成数据库设计和实施，并实现具有较完善功能的、方便最终用户使用的应用系统。\n实验环境：MS Access或者Microsoft SQL Server 2008等。\n开发语言：Visual FoxPro，PowerBuilder，VisualBasic，JBuilder，IDL或VC++等。如果条件许可，也可以开发基于C/S架构的数据库应用系统。\n利用所熟悉的DBMS建立数据库，利用指定的开发环境来开发具有美观、大方、操作方便的图形用户界面的数据库管理应用系统。\n\n九、考核方式及成绩评定\n考核方式：系统验收，实验报告\n成绩评定标准：总成绩（五级制）＝系统验收成绩×70％＋实验报告成绩×30％。\n\n十、教材及主要参考书\n指定教材：\n[1]、韩培友，数据库技术，西安：西北工业大学出版社，第1版，2008.12\n参考书目：\n[1]、丁宝康，数据库实用教程，北京：清华大学出版社，第2版，2003．2\n[2]、周绪，管丽娜，白海波，SQL Server 2000 入门与提高，北京：清华大学出版社，第一版，2001.6\n[3]、王珊等，数据库系统概论，北京：高等教育出版社，第5版，2014.9\n[4]、韩培友，《数据库技术习题与实验》，杭州：浙江工商大学出版社，第1版，2010.8\n', '0', '0', '', '2026-04-08 20:54:06', '', '2026-04-09 18:36:45', NULL);

-- ----------------------------
-- Table structure for sys_config
-- ----------------------------
DROP TABLE IF EXISTS `sys_config`;
CREATE TABLE `sys_config`  (
  `config_id` int NOT NULL AUTO_INCREMENT COMMENT '参数主键',
  `config_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '参数名称',
  `config_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '参数键名',
  `config_value` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '参数键值',
  `config_type` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'N' COMMENT '系统内置（Y是 N否）',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`config_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 100 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '参数配置表' ROW_FORMAT = Dynamic;

