INSERT INTO `sys_oper_log` VALUES (302, '通知公告', 2, 'com.ruoyi.web.controller.system.SysNoticeController.edit()', 'PUT', 1, 'admin', '研发部门', '/system/notice', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-04-05 01:24:56\",\"isRead\":false,\"noticeContent\":\"<h2><span style=\\\"color: inherit;\\\">课程目标达成情况分析系统</span></h2><p><span style=\\\"color: rgb(103, 106, 108);\\\">一个辅助教师生成 “课程目标达成情况分析报告” 的系统，实现教学目标与试卷关联、学生成绩自动导入、达成度计算、报告自动生成等功能，LLM 用于生成并优化报告表述。</span></p><h2><span style=\\\"color: inherit;\\\">技术选型</span></h2><h4><span style=\\\"color: inherit;\\\">后端技术</span></h4><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">SpringBoot</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Spring Security</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">JWT</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">MyBatis</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Druid</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Fastjson</span></li></ol><h4><span style=\\\"color: inherit;\\\">前端技术</span></h4><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Vue</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Vuex</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Element-ui</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Axios</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Sas', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-04-12 14:14:06', 26);
INSERT INTO `sys_oper_log` VALUES (303, '通知公告', 2, 'com.ruoyi.web.controller.system.SysNoticeController.edit()', 'PUT', 1, 'admin', '研发部门', '/system/notice', '127.0.0.1', '内网IP', '{\"createBy\":\"admin\",\"createTime\":\"2026-04-05 01:24:56\",\"isRead\":false,\"noticeContent\":\"<h2><span style=\\\"color: inherit;\\\">课程目标达成情况分析系统</span></h2><p><span style=\\\"color: rgb(103, 106, 108);\\\">一个辅助教师生成 “课程目标达成情况分析报告” 的系统，实现教学目标与试卷关联、学生成绩自动导入、达成度计算、报告自动生成等功能，LLM 用于生成并优化报告表述。</span></p><h2><span style=\\\"color: inherit;\\\">技术选型</span></h2><h4><span style=\\\"color: inherit;\\\">后端技术</span></h4><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">SpringBoot</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Spring Security</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">JWT</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">MyBatis</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Druid</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Fastjson</span></li></ol><h4><span style=\\\"color: inherit;\\\">前端技术</span></h4><ol><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Vue</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Vuex</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Element-ui</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Axios</span></li><li data-list=\\\"bullet\\\"><span class=\\\"ql-ui\\\" contenteditable=\\\"false\\\"></span><span style=\\\"color: rgb(103, 106, 108);\\\">Sas', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-04-12 14:14:17', 10);
